function LeafO({ size = 18, color = BRAND.forest }) {
  return (
    <span style={{ position: "relative", display: "inline-block" }}>
      O
      <svg
        width={size * 0.55}
        height={size * 0.55}
        viewBox="0 0 24 24"
        style={{ position: "absolute", top: -size * 0.32, right: -size * 0.12 }}
      >
        <path d="M12 21 C 5 15, 7 6, 16 3 C 18 10, 16 17, 12 21 Z" fill={color} />
        <path d="M12 20 C 13 15, 14 10, 16 5" stroke={BRAND.oliveSoft} strokeWidth="1" fill="none" />
      </svg>
    </span>
  );
}

