// ─────────────────────────────────────────────────────────────
// Markdown export (handles both section types — pastes into Skool)
// ─────────────────────────────────────────────────────────────
function toMarkdown(doc, seriesLabel) {
  const lines = [`**OLYVECO** — *${seriesLabel}*`, "", `# ${doc.title}`, `*${doc.subtitle}*`, ""];
  (doc.standfirst || []).forEach((p) => {
    lines.push(p);
    lines.push("");
  });
  (doc.sections || []).forEach((s) => {
    lines.push(`## ${s.heading}`);
    lines.push(`*${s.subtitle}*`);
    lines.push("");
    if (s.type === "paths") {
      (s.paths || []).forEach((p) => {
        lines.push(`**${p.number}. ${p.title}**`);
        lines.push(`*The fear it answers: ${p.fear}*`);
        lines.push(p.intro);
        lines.push(`- **Ask:** ${p.ask}`);
        lines.push(`- **The costly mistake:** ${p.mistake}`);
        lines.push("");
      });
    } else {
      (s.items || []).forEach((it) => lines.push(`- **${it.lead}.** ${it.body}`));
      lines.push("");
    }
  });
  if (doc.closing) {
    lines.push(`> **${doc.closing.heading}** — ${doc.closing.body}`);
    lines.push("");
  }
  lines.push(`*${doc.disclaimer}*`);
  return lines.join("\n");
}

// ─────────────────────────────────────────────────────────────
// Word-safe HTML export — no flexbox, hanging-indent bullets,
// so everything lines up when opened in Word / Google Docs.
// ─────────────────────────────────────────────────────────────
function buildExportHtml(doc, seriesLabel) {
  const esc = (s) =>
    String(s || "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
  const bullet = (lead, bodyText) =>
    `<p style="margin:0 0 6pt 22pt;text-indent:-11pt;font-size:10.5pt;line-height:1.5;mso-line-height-rule:exactly;">` +
    `<span style="color:${BRAND.forest};">&bull;&nbsp;</span>` +
    `<b style="color:${BRAND.forestDark};">${esc(lead)}. </b>${esc(bodyText)}</p>`;

  let out = "";
  out += `<img src="${LOGO}" alt="OLYVECO" width="190" style="width:190px;height:auto;" />`;
  out += `<p style="margin:3pt 0 0;font-size:9.5pt;font-style:italic;color:${BRAND.muted};border-bottom:2pt solid ${BRAND.forest};padding-bottom:4pt;">${esc(seriesLabel)}</p>`;
  out += `<h1 style="font-family:Georgia,serif;font-size:22pt;color:${BRAND.forestDark};margin:18pt 0 4pt;">${esc(doc.title)}</h1>`;
  out += `<p style="font-size:12pt;font-style:italic;color:${BRAND.forest};margin:0 0 12pt;">${esc(doc.subtitle)}</p>`;
  (doc.standfirst || []).forEach((p) => {
    out += `<p style="font-size:10.5pt;line-height:1.6;margin:0 0 8pt;">${esc(p)}</p>`;
  });
  (doc.sections || []).forEach((sec) => {
    out += `<p style="margin:16pt 0 2pt;padding-bottom:2pt;border-bottom:1pt solid ${BRAND.forest};color:${BRAND.forest};font-weight:bold;font-size:10.5pt;letter-spacing:2pt;">${esc(sec.heading).toUpperCase()}</p>`;
    out += `<p style="font-size:9.5pt;font-style:italic;color:${BRAND.muted};margin:0 0 8pt;">${esc(sec.subtitle)}</p>`;
    if (sec.type === "paths") {
      (sec.paths || []).forEach((p) => {
        out += `<p style="font-size:13pt;font-weight:bold;margin:12pt 0 2pt;"><span style="color:${BRAND.forest};">${esc(p.number)}.</span> <span style="color:${BRAND.forestDark};">${esc(p.title)}</span></p>`;
        out += `<p style="font-size:9.5pt;font-style:italic;margin:0 0 5pt;"><b style="color:${BRAND.forest};">The fear it answers: </b><span style="color:${BRAND.muted};">${esc(p.fear)}</span></p>`;
        out += `<p style="font-size:10.5pt;line-height:1.6;margin:0 0 6pt;">${esc(p.intro)}</p>`;
        out += bullet("Ask", p.ask);
        out += bullet("The costly mistake", p.mistake);
      });
    } else {
      (sec.items || []).forEach((it) => {
        out += bullet(it.lead, it.body);
      });
    }
  });
  if (doc.closing) {
    out +=
      `<table width="100%" cellpadding="0" cellspacing="0" style="margin-top:16pt;border-top:2pt solid ${BRAND.forest};border-bottom:2pt solid ${BRAND.forest};"><tr>` +
      `<td style="background:${BRAND.oliveSoft};padding:10pt 12pt;">` +
      `<p style="font-weight:bold;color:${BRAND.forestDark};font-size:11pt;margin:0 0 4pt;">${esc(doc.closing.heading)}</p>` +
      `<p style="font-size:10.5pt;line-height:1.6;margin:0;">${esc(doc.closing.body)}</p>` +
      `</td></tr></table>`;
  }
  out += `<p style="margin-top:14pt;font-size:8.5pt;font-style:italic;color:${BRAND.muted};">${esc(doc.disclaimer)}</p>`;
  return (
    `<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:w="urn:schemas-microsoft-com:office:word">` +
    `<head><meta charset="utf-8"><title>${esc(doc.title)}</title></head>` +
    `<body style="font-family:Georgia,serif;color:${BRAND.ink};margin:0;">${out}</body></html>`
  );
}

