export default function OlyvecoStudio() {
  const [productType, setProductType] = useState("guide");
  const [title, setTitle] = useState("");
  const [audience, setAudience] = useState("Homeowners facing the Stay vs. Go decision");
  const [series, setSeries] = useState(STAY_OR_GO_WELCOME.series);
  const [notes, setNotes] = useState("");
  const [editorNotes, setEditorNotes] = useState("");
  const [doc, setDoc] = useState(STAY_OR_GO_WELCOME);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [copied, setCopied] = useState(false);

  const loadFromLibrary = (item) => {
    setDoc(item);
    setSeries(item.series || "Homeowner Education Series");
    setError("");
  };

  const generate = async () => {
    if (!notes.trim()) {
      setError("Add your raw content or notes first — the studio needs material to work from.");
      return;
    }
    setLoading(true);
    setError("");
    try {
      const typeLabel = PRODUCT_TYPES.find((t) => t.id === productType)?.label || "Education Guide";
      const userPrompt = [
        `PRODUCT TYPE: ${typeLabel}`,
        `AUDIENCE: ${audience || "Homeowners"}`,
        title.trim() ? `WORKING TITLE (refine if you can improve it): ${title}` : `TITLE: propose one`,
        editorNotes.trim() ? `EDITOR NOTES: ${editorNotes}` : "",
        "",
        "RAW CONTENT / NOTES:",
        notes,
      ]
        .filter(Boolean)
        .join("\n");

      const response = await fetch("/api/generate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-6",
          max_tokens: 1000,
          system: VOICE_SYSTEM_PROMPT,
          messages: [{ role: "user", content: userPrompt }],
        }),
      });

      const data = await response.json();
      const text = (data.content || [])
        .filter((b) => b.type === "text")
        .map((b) => b.text)
        .join("\n");
      const clean = text.replace(/```json|```/g, "").trim();
      const parsed = JSON.parse(clean);
      setDoc(parsed);
    } catch (err) {
      console.error("Generation error:", err);
      setError("Something went wrong assembling the document. Try again, or shorten your notes slightly.");
    } finally {
      setLoading(false);
    }
  };

  const printDoc = () => {
    const el = document.getElementById("olyveco-document");
    if (!el) return;
    setError("");
    // Print via a hidden iframe — no pop-up window, so browsers never block it.
    const frame = document.createElement("iframe");
    frame.setAttribute("aria-hidden", "true");
    frame.style.position = "fixed";
    frame.style.right = "0";
    frame.style.bottom = "0";
    frame.style.width = "0";
    frame.style.height = "0";
    frame.style.border = "0";
    document.body.appendChild(frame);
    try {
      const fdoc = frame.contentWindow.document;
      fdoc.open();
      fdoc.write(
        `<html><head><title>${doc?.title || "Olyveco Document"}</title>` +
          `<style>#olyveco-document{box-shadow:none !important;} @page{margin:0.6in;} body{margin:0;background:#fff;}</style>` +
          `</head><body>${el.outerHTML}</body></html>`
      );
      fdoc.close();
      frame.contentWindow.focus();
      setTimeout(() => {
        try {
          frame.contentWindow.print();
        } catch {
          setError("Printing isn't available in this browser — use Copy for Skool instead.");
        }
        // Give the print dialog time to capture the frame before removing it.
        setTimeout(() => {
          if (frame.parentNode) frame.parentNode.removeChild(frame);
        }, 60000);
      }, 300);
    } catch {
      if (frame.parentNode) frame.parentNode.removeChild(frame);
      setError("Printing isn't available in this browser — use Copy for Skool instead.");
    }
  };

  const copyMarkdown = async () => {
    if (!doc) return;
    try {
      await navigator.clipboard.writeText(toMarkdown(doc, series));
      setCopied(true);
      setTimeout(() => setCopied(false), 1800);
    } catch {
      setError("Copy failed — your browser may be blocking clipboard access.");
    }
  };

  const downloadDoc = () => {
    if (!doc) return;
    setError("");
    try {
      // Word-safe HTML (built from the document data, not the on-screen layout)
      // so bullets keep their hanging indent in Word, Google Docs, and Pages.
      const fullHtml = buildExportHtml(doc, series);
      const blob = new Blob(["\ufeff", fullHtml], { type: "application/msword" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = `${(doc.title || "Olyveco Document").replace(/[^a-z0-9]+/gi, "_")}.doc`;
      document.body.appendChild(a);
      a.click();
      a.remove();
      URL.revokeObjectURL(url);
    } catch {
      setError("Download didn't start — use Print / Save PDF or Copy for Skool instead.");
    }
  };

  const chrome = {
    label: {
      display: "block",
      fontFamily: BRAND.sans,
      fontSize: 11,
      fontWeight: 600,
      letterSpacing: "0.08em",
      textTransform: "uppercase",
      color: BRAND.muted,
      marginBottom: 5,
    },
    input: {
      width: "100%",
      boxSizing: "border-box",
      fontFamily: BRAND.sans,
      fontSize: 13.5,
      padding: "9px 11px",
      border: `1px solid ${BRAND.oliveLine}`,
      borderRadius: 6,
      background: "#fff",
      color: BRAND.ink,
      outline: "none",
    },
    field: { marginBottom: 16 },
  };

  return (
    <div style={{ minHeight: "100vh", background: BRAND.paper, display: "flex", flexWrap: "wrap" }}>
      {/* ── LEFT: Studio panel ─────────────────────────────── */}
      <div
        style={{
          flex: "1 1 340px",
          maxWidth: 440,
          minWidth: 320,
          padding: "28px 26px 40px",
          borderRight: `1px solid ${BRAND.oliveLine}`,
          background: "#fff",
        }}
      >
        <img src={LOGO} alt="OLYVECO" style={{ height: 30, width: "auto", display: "block", marginBottom: 4 }} />
        <div style={{ fontFamily: BRAND.sans, fontSize: 12, color: BRAND.muted, marginBottom: 22 }}>
          Product Studio — brand-locked document builder
        </div>

        {/* Brand kit strip */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 10,
            background: BRAND.oliveSoft,
            border: `1px solid ${BRAND.oliveLine}`,
            borderRadius: 8,
            padding: "10px 12px",
            marginBottom: 18,
          }}
        >
          {[BRAND.forestDark, BRAND.forest, BRAND.oliveLine, BRAND.oliveSoft].map((c) => (
            <span key={c} style={{ width: 18, height: 18, borderRadius: "50%", background: c, border: "1px solid rgba(0,0,0,0.12)" }} />
          ))}
          <span style={{ fontFamily: BRAND.sans, fontSize: 11.5, color: BRAND.muted }}>
            Forest green · Georgia serif · editorial, advisory voice
          </span>
        </div>

        {/* Document library */}
        <div style={{ marginBottom: 20 }}>
          <span style={chrome.label}>Document library</span>
          {LIBRARY.map((item) => (
            <button
              key={item.id}
              onClick={() => loadFromLibrary(item)}
              style={{
                width: "100%",
                textAlign: "left",
                fontFamily: BRAND.sans,
                fontSize: 12.5,
                padding: "10px 12px",
                borderRadius: 6,
                cursor: "pointer",
                border: `1px solid ${doc?.id === item.id ? BRAND.forest : BRAND.oliveLine}`,
                background: doc?.id === item.id ? BRAND.oliveSoft : "#fff",
                color: BRAND.ink,
              }}
            >
              <span style={{ fontWeight: 600, color: BRAND.forestDark }}>{item.title}</span>
              <span style={{ display: "block", fontSize: 11, color: BRAND.muted, marginTop: 2 }}>
                {item.series} · built-in branded document
              </span>
            </button>
          ))}
        </div>

        {/* Product type */}
        <div style={chrome.field}>
          <span style={chrome.label}>Create new — product type</span>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
            {PRODUCT_TYPES.map((t) => (
              <button
                key={t.id}
                onClick={() => setProductType(t.id)}
                title={t.hint}
                style={{
                  fontFamily: BRAND.sans,
                  fontSize: 12.5,
                  padding: "9px 8px",
                  borderRadius: 6,
                  cursor: "pointer",
                  border: `1px solid ${productType === t.id ? BRAND.forest : BRAND.oliveLine}`,
                  background: productType === t.id ? BRAND.forest : "#fff",
                  color: productType === t.id ? "#fff" : BRAND.ink,
                  transition: "all 0.15s",
                }}
              >
                {t.label}
              </button>
            ))}
          </div>
        </div>

        <div style={chrome.field}>
          <span style={chrome.label}>Working title (optional)</span>
          <input style={chrome.input} value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Leave blank and the studio will propose one" />
        </div>

        <div style={chrome.field}>
          <span style={chrome.label}>Audience</span>
          <input style={chrome.input} value={audience} onChange={(e) => setAudience(e.target.value)} />
        </div>

        <div style={chrome.field}>
          <span style={chrome.label}>Series label (masthead)</span>
          <input style={chrome.input} value={series} onChange={(e) => setSeries(e.target.value)} />
        </div>

        <div style={chrome.field}>
          <span style={chrome.label}>Raw content or notes</span>
          <textarea
            style={{ ...chrome.input, minHeight: 150, resize: "vertical", lineHeight: 1.5 }}
            value={notes}
            onChange={(e) => setNotes(e.target.value)}
            placeholder={"Paste draft text, bullet points, or rough notes.\nThe studio rewrites it in the Olyveco voice and lays it into the template."}
          />
        </div>

        <div style={chrome.field}>
          <span style={chrome.label}>Notes to the editor (optional)</span>
          <input
            style={chrome.input}
            value={editorNotes}
            onChange={(e) => setEditorNotes(e.target.value)}
            placeholder='e.g. "keep it to 3 sections" or "warmer tone"'
          />
        </div>

        <button
          onClick={generate}
          disabled={loading}
          style={{
            width: "100%",
            fontFamily: BRAND.sans,
            fontSize: 14,
            fontWeight: 600,
            padding: "12px",
            borderRadius: 7,
            border: "none",
            cursor: loading ? "wait" : "pointer",
            background: loading ? BRAND.muted : BRAND.forest,
            color: "#fff",
            letterSpacing: "0.03em",
          }}
        >
          {loading ? "Writing in the Olyveco voice…" : "Build new document"}
        </button>

        {error && (
          <p style={{ fontFamily: BRAND.sans, fontSize: 12.5, color: "#8A3B2E", marginTop: 12, lineHeight: 1.5 }}>{error}</p>
        )}

        {doc && (
          <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginTop: 12 }}>
            <button
              onClick={downloadDoc}
              style={{ flex: "1 1 100%", fontFamily: BRAND.sans, fontSize: 13, padding: "10px", borderRadius: 7, border: "none", background: BRAND.forestDark, color: "#fff", cursor: "pointer", fontWeight: 600 }}
            >
              Download document (Word)
            </button>
            <button
              onClick={printDoc}
              style={{ flex: 1, fontFamily: BRAND.sans, fontSize: 13, padding: "10px", borderRadius: 7, border: `1px solid ${BRAND.forest}`, background: "#fff", color: BRAND.forest, cursor: "pointer", fontWeight: 600 }}
            >
              Print / Save PDF
            </button>
            <button
              onClick={copyMarkdown}
              style={{ flex: 1, fontFamily: BRAND.sans, fontSize: 13, padding: "10px", borderRadius: 7, border: `1px solid ${BRAND.forest}`, background: "#fff", color: BRAND.forest, cursor: "pointer", fontWeight: 600 }}
            >
              {copied ? "Copied ✓" : "Copy for Skool"}
            </button>
          </div>
        )}

        <p style={{ fontFamily: BRAND.sans, fontSize: 11, color: BRAND.muted, marginTop: 18, lineHeight: 1.5 }}>
          Built-in library documents are always here. Newly generated documents live in this session only — print or copy anything you want to keep. "Copy for Skool" produces formatted markdown that pastes cleanly into your classroom.
        </p>
      </div>

      {/* ── RIGHT: Live document preview ───────────────────── */}
      <div style={{ flex: "2 1 520px", padding: "36px 28px", overflowY: "auto" }}>
        {doc ? (
          <DocumentPreview doc={doc} seriesLabel={series} />
        ) : (
          <div style={{ maxWidth: 760, margin: "60px auto", textAlign: "center", fontFamily: BRAND.serif, color: BRAND.muted }}>
            <div style={{ fontSize: 44, color: BRAND.forest, letterSpacing: "0.2em", marginBottom: 14 }}>
              <LeafO size={44} />
            </div>
            <p style={{ fontSize: 17, fontStyle: "italic", lineHeight: 1.7, maxWidth: 420, margin: "0 auto" }}>
              Your document preview appears here — laid out in the Olyveco editorial template, written in the voice that replaces fear with confidence.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}
